class VectorIndex {
  constructor(projectPath) {
    this.projectPath = projectPath;
    this.indexPath = path.join(projectPath, 'data', 'vectors');
    this.indexFile = path.join(this.indexPath, 'index.json');
    this.vectors = [];
    this.documents = [];
  }

  /**
   * 加载或创建索引
   */
  async load() {
    if (fs.existsSync(this.indexFile)) {
      const data = JSON.parse(fs.readFileSync(this.indexFile, 'utf-8'));
      this.vectors = data.vectors || [];
      this.documents = data.documents || [];
      return true;
    }
    return false;
  }

  /**
   * 保存索引
   */
  save() {
    if (!fs.existsSync(this.indexPath)) {
      fs.mkdirSync(this.indexPath, { recursive: true });
    }
    fs.writeFileSync(this.indexFile, JSON.stringify({
      vectors: this.vectors,
      documents: this.documents,
    }, null, 2), 'utf-8');
  }

  /**
   * 从项目文件构建索引
   */
  async build() {
    this.vectors = [];
    this.documents = [];

    // 读取事实台账
    const factsPath = path.join(this.projectPath, 'facts');
    if (fs.existsSync(factsPath)) {
      // 角色事实
      const charFactsFile = path.join(factsPath, 'characters_facts.yaml');
      if (fs.existsSync(charFactsFile)) {
        const charFacts = yaml.load(fs.readFileSync(charFactsFile, 'utf-8'));
        for (const [name, fact] of Object.entries(charFacts)) {
          const f = fact || {};
          const text = `${name} ${f.mbti || ''} ${f.core_fear || ''} ${(f.abilities || []).join(' ')} ${f.goal || ''}`;
          await this.addDocument(text, { type: 'character', name });
        }
      }

      // 设定事实
      const settingsFactsFile = path.join(factsPath, 'settings_facts.yaml');
      if (fs.existsSync(settingsFactsFile)) {
        const settingsFacts = yaml.load(fs.readFileSync(settingsFactsFile, 'utf-8'));
        for (const [name, fact] of Object.entries(settingsFacts)) {
          const f = fact || {};
          const text = `${name} ${f.type || ''} ${f.description || ''} ${(f.rules || []).join(' ')}`;
          await this.addDocument(text, { type: 'setting', name });
        }
      }

      // 情节事实
      const plotsFactsFile = path.join(factsPath, 'plot_facts.yaml');
      if (fs.existsSync(plotsFactsFile)) {
        const plotsFacts = yaml.load(fs.readFileSync(plotsFactsFile, 'utf-8'));
        if (plotsFacts && plotsFacts.伏笔清单) {
          for (const fb of plotsFacts.伏笔清单) {
            const text = `${fb.description || ''} ${fb.details || ''}`;
            await this.addDocument(text, { type: 'foreshadowing', id: fb.id });
          }
        }
      }
    }

    // 读取章节摘要
    const plotsDir = path.join(this.projectPath, 'plots');
    if (fs.existsSync(plotsDir)) {
      const volumes = fs.readdirSync(plotsDir).filter(item => {
        const itemPath = path.join(plotsDir, item);
        return fs.statSync(itemPath).isDirectory() && !item.startsWith('_');
      });

      for (const volume of volumes) {
        const summaryFile = path.join(plotsDir, volume, '_summaries.yaml');
        if (fs.existsSync(summaryFile)) {
          const summaries = yaml.load(fs.readFileSync(summaryFile, 'utf-8'));
          for (const [key, summary] of Object.entries(summaries || {})) {
            const chapterNum = key.replace('chapter_', '');
            await this.addDocument(summary, { type: 'summary', volume, chapter: chapterNum });
          }
        }
      }
    }

    this.save();
    return this.documents.length;
  }

  /**
   * 添加文档到索引
   */
  async addDocument(text, metadata) {
    const vector = await embedText(text);
    this.vectors.push(vector);
    this.documents.push({ text, ...metadata });
  }

  /**
   * 搜索相似文档
   */
  async search(query, topK = 5) {
    if (this.vectors.length === 0) {
      await this.load();
    }

    const queryVector = await embedText(query);

    // 计算余弦相似度
    const scores = this.vectors.map((vector, i) => ({
      index: i,
      score: this.cosineSimilarity(queryVector, vector),
    }));

    // 排序并返回 topK
    scores.sort((a, b) => b.score - a.score);
    return scores.slice(0, topK).map(s => ({
      ...this.documents[s.index],
      score: s.score,
    }));
  }

  /**
   * 计算余弦相似度
   */
  cosineSimilarity(a, b) {
    let dotProduct = 0;
    let normA = 0;
    let normB = 0;
    for (let i = 0; i < a.length; i++) {
      dotProduct += a[i] * b[i];
      normA += a[i] * a[i];
      normB += b[i] * b[i];
    }
    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
  }

  /**
   * 清除索引
   */
  clear() {
    this.vectors = [];
    this.documents = [];
    if (fs.existsSync(this.indexFile)) {
      fs.unlinkSync(this.indexFile);
    }
  }
}

